import './App.css';
import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text } from "@radix-ui/themes";

function App() {
  return (
    <Theme accentColor="yellow" panelBackground="solid" radius="full">
      <Box style={{ background: "var(--gray-a2)", borderRadius: "var(--radius-3)" }}>
        <Container size="1">
          <Flex justify="center" direction="column" gap="2">
            <Text>Hello from Radix Themes :)</Text>
            <Button>Let's go</Button>
          </Flex>
          <Box py="9" />
          <ThemePanel />
        </Container>
      </Box>
    </Theme>
  );
}

export default App;
